import { useState, useEffect, useCallback, useRef } from "react"; // Tambahkan useCallback, useRef
import { ethers } from "ethers";
import { TEQOIN_CHAIN } from "../config/constants";

export default function useWallet() {
  const [wallet,    setWallet]   = useState(null);
  const [signer,    setSigner]   = useState(null);
  const [provider, setProvider] = useState(null);
  const [wrongChain, setWrongChain] = useState(false);

  // --- Tambahkan ini untuk Toast ---
  const [toast, setToast] = useState(null);
  const timerRef = useRef(null);

  const showToast = useCallback((msg, type = "ok") => {
    if (timerRef.current) clearTimeout(timerRef.current);
    setToast({ msg, type });
    timerRef.current = setTimeout(() => setToast(null), 4000);
  }, []);
  // ---------------------------------

  // ... useEffect dan fungsi initWallet/connect yang sudah ada ...
  // (Pastikan kode useEffect dan lainnya tidak dihapus)

  // Update return agar menyertakan toast dan showToast
  return { 
    wallet, signer, provider, wrongChain, connect, 
    toast, showToast 
  };
}
